import React, { useState } from 'react';
import { ChevronLeft, Banknote, CheckCircle2, Info } from 'lucide-react';

/**
 * LoanApplicationScreen Component
 * A streamlined application flow for credit products.
 */
const LoanApplicationScreen = ({ loanType, onBack, onComplete }) => {
  const [step, setStep] = useState(1);
  const type = loanType || "Business Expansion";

  return (
    <div className="flex flex-col bg-white animate-in slide-in-from-right duration-300">
      {/* Header */}
      <div className="flex items-center gap-3 px-6 py-4 sticky top-0 bg-white z-10 border-b border-gray-50">
        <button onClick={onBack} className="p-2 hover:bg-gray-100 rounded-full transition-colors">
          <ChevronLeft className="w-6 h-6 text-gray-800" />
        </button>
        <h1 className="text-xl font-black text-gray-900">Application</h1>
      </div>

      {/* Content */}
      <div className="p-6 flex-1 overflow-y-auto scrollbar-hide">
        {/* Step Indicator */}
        <div className="flex gap-2 mb-8">
          {[1, 2, 3].map((s) => (
            <div 
              key={s} 
              className={`h-1.5 flex-1 rounded-full transition-all duration-500 ${s <= step ? 'bg-[#00875A]' : 'bg-gray-100'}`}
            />
          ))}
        </div>

        {/* Step 1: Loan Details */}
        {step === 1 && (
          <div className="animate-in fade-in slide-in-from-bottom-4 duration-500">
            <h2 className="text-2xl font-black text-gray-900 mb-2">Loan Details</h2>
            <p className="text-gray-400 font-bold text-sm mb-8">
              Confirm the amount and duration for your {type} loan.
            </p>

            <div className="space-y-6">
              <div className="space-y-2">
                <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1">
                  Requested Amount
                </label>
                <div className="p-6 bg-gray-50 rounded-[2rem] border border-gray-100">
                  <span className="text-4xl font-black text-gray-900">$25,000</span>
                </div>
              </div>

              <div className="space-y-2">
                <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1">
                  Repayment Period
                </label>
                <select className="w-full p-5 rounded-[1.8rem] bg-gray-50 border border-gray-100 font-bold outline-none focus:border-[#00875A] appearance-none">
                  <option>12 Months (5% Interest)</option>
                  <option>24 Months (7% Interest)</option>
                  <option>36 Months (9% Interest)</option>
                </select>
              </div>

              <div className="p-5 bg-emerald-50 rounded-[2rem] border border-emerald-100 flex gap-4">
                <Info className="text-[#00875A] shrink-0" size={20} />
                <p className="text-xs text-emerald-800 font-bold leading-relaxed">
                  Your monthly repayment will be <span className="font-black">$2,187.50</span> starting next month.
                </p>
              </div>
            </div>
          </div>
        )}

        {/* Step 2: Verification */}
        {step === 2 && (
          <div className="animate-in fade-in slide-in-from-bottom-4 duration-500">
            <h2 className="text-2xl font-black text-gray-900 mb-2">Verification</h2>
            <p className="text-gray-400 font-bold text-sm mb-8">
              We use your Nest history to fast-track your approval.
            </p>

            <div className="space-y-4">
              {['Identity Verified', 'Income Verified', 'Credit Check Pass'].map((check, i) => (
                <div key={i} className="flex items-center justify-between p-5 border border-gray-100 rounded-[1.8rem]">
                  <span className="font-black text-gray-800">{check}</span>
                  <CheckCircle2 className="text-[#00875A]" size={20} />
                </div>
              ))}
            </div>
          </div>
        )}

        {/* Step 3: Completion / Summary */}
        {step === 3 && (
          <div className="animate-in fade-in slide-in-from-bottom-4 duration-500 text-center">
            <Banknote className="w-16 h-16 mx-auto text-[#00875A] mb-6" />
            <h2 className="text-2xl font-black text-gray-900 mb-2">All Set!</h2>
            <p className="text-gray-500 font-bold text-sm">
              Your loan application has been submitted successfully. You will receive notifications about approval status.
            </p>
          </div>
        )}
      </div>

      {/* Footer Button */}
      <div className="p-6 border-t border-gray-50">
        <button 
          onClick={() => {
            if (step < 3) setStep(step + 1);
            else onComplete?.();
          }}
          className="w-full py-5 rounded-[2rem] font-black text-white bg-[#00875A] shadow-xl shadow-emerald-100 active:scale-[0.98] transition-all"
        >
          {step === 1 ? 'Continue' : step === 2 ? 'Submit Application' : 'Done'}
        </button>
      </div>
    </div>
  );
};

export default LoanApplicationScreen;
